var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어떻게 된 거지? 냉기가 생각대로 움직이지 않아.","JPN":"どういうこと？　冷気が思いどおり動かせないわ。","ENG":"I do not understand... Why can I not use my frost powers?","TWN":"怎麼回事？寒氣不受控制。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이제까지 이런 적은 한 번도 없었는데, 어째서……!","JPN":"今までこんなことなかったのに、どうして……！","ENG":"This has never happened once...! Why?!","TWN":"以前從來沒出現過這種情況，為什麼……！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"냉기를 두려워하지 마라! 다들 부학회장님을 붙잡아!","JPN":"冷気を恐れるな！　副学会長を捕らえろ！","ENG":"Don't fear the frost! Men, grab her!","TWN":"別怕她的寒氣！大家一起抓住副學會長！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_A","text":{"KOREA":"죄송합니다, 부학회장님!","JPN":"申し訳ございません、副学会長！","ENG":"I'm so sorry, Vice President!","TWN":"抱歉，副學會長！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이거 놓지 못해?! 어디 숙녀 손목을 함부로 잡아요!","JPN":"放しなさい！！　淑女の手首を掴むとは何事ですの！","ENG":"Let go! How dare you lay hands on a lady!!","TWN":"放開我？！是誰允許你們隨便抓住淑女的手腕的！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_C","text":{"KOREA":"한두 명으로는 역부족이다! 전원 가세해!","JPN":"一人二人だけでは足りない！　全員、加勢しろ！","ENG":"Two men aren't enough to hold her down! Everyone, grab her!","TWN":"一兩個人不夠！大家一起上！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"자, 잠깐만요? 저 하나 붙잡자고 도대체 몇 명이…","JPN":"ちょ、ちょっと？　私一人捕まえるのに一体何人……","ENG":"W-wait! How many of you are coming to–","TWN":"等…等一下？為了抓住我，這麼多人一起上也……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"꺄악!?","JPN":"きゃあっ！？","ENG":"Kyaah!","TWN":"哎呀！？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"세상에, 부학회장님….","JPN":"まあ、副学会長様……","ENG":"Oh dear, Vice President...","TWN":"天啊，副學會長……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님이 힘들어하시잖아요! 어서 놓아 주세요!","JPN":"副学会長様が痛がってらっしゃるじゃないですか！　早くお放しください！","ENG":"Can't you see you're stressing her?! Let go of her!","TWN":"副學會長很難受！快點放開她！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"시끄럽다. 영지에서 따라온 주민 같은데, 지금 학회 일에 끼어들겠다는 건가?","JPN":"うるさい。領地からついてきた住民のようだが、学会のことに口を挟む気か？","ENG":"Silence. You look like a resident from the estate, and are you trying to interfere with Society business?","TWN":"閉嘴。你是從領地過來的居民吧，現在想插手學會的事嗎？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"그대로 침실로 모셔라. 조금 불편해하셔도 상관없다.","JPN":"そのまま寝室にお連れしろ。少々ご不満を訴えられるかもしれないが、構わない。","ENG":"Take her to her bed. Be a little rough if you have to.","TWN":"直接送回臥室。有點不舒服也沒關係。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"조금이 아니라 많이 불편하다고요!","JPN":"少々どころか大いに不満ですわ！","ENG":"You call this a little? You are practically crushing me!","TWN":"不是有點，是非常不舒服！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"묻는 말엔 입 꾹 다물고 자기 할말만 하면 다야?! 대답 못하겠으면 에델이라도 데려와요!","JPN":"私の問いには口を固く閉ざして、そちらの言いたいことだけ言うのですか！？　答えられないのならエデルでも連れてきなさい！","ENG":"You ignore my questions and only say what you need?! If you cannot answer me, bring Edel to me!","TWN":"對我的問話拒不回答，只願意說自己想說的話嗎？！如果答不上來，就帶艾瑟兒過來！"},"stage":{"bg":"CORRIDOR_06","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_QM","text":{"KOREA":"뭐야, 뭐야? 왜 이리 시끄러워? 나 빼놓고 파티 연 거 아니지?","JPN":"なになに？　なんでこんなに騒がしいの？　アタシだけのけ者にしてパーティーでもしてるんじゃないよね？","ENG":"Huh? What's going on here? What's all the ruckus about? Are you all having a party without me?","TWN":"怎麼回事，怎麼回事？為什麼這麼吵？不會背著我開派對吧？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"아. 오셨군요. 루나 님.","JPN":"あ。おいででしたか。ルナ様。","ENG":"Oh, you're here, Ms. Luna.","TWN":"啊，你來了，露娜。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};